#!/usr/bin/env node
/**
 * bundle-migrations.js
 * ─────────────────────
 * Reads all Prisma migration SQL files and writes them into a single
 * TypeScript source file (src/migrations-bundle.ts) as embedded strings.
 *
 * This means the runtime code never needs to find files inside the pkg
 * snapshot — it just imports a plain JS module with the SQL already in it.
 *
 * Run automatically as part of `npm run build:binary` via build-sidecar.js.
 * Also safe to run standalone: node scripts/bundle-migrations.js
 */

const fs   = require('fs');
const path = require('path');

const ROOT       = path.resolve(__dirname, '..');
const MIGRATIONS = path.join(ROOT, 'prisma', 'migrations');
const OUT_FILE   = path.join(ROOT, 'src', 'migrations-bundle.ts');

if (!fs.existsSync(MIGRATIONS)) {
  console.error('❌ prisma/migrations not found at', MIGRATIONS);
  process.exit(1);
}

const dirs = fs
  .readdirSync(MIGRATIONS)
  .filter(d => fs.statSync(path.join(MIGRATIONS, d)).isDirectory())
  .sort();

if (dirs.length === 0) {
  console.warn('⚠️  No migration folders found — writing empty bundle.');
}

const migrations = dirs
  .map(name => {
    const sqlFile = path.join(MIGRATIONS, name, 'migration.sql');
    if (!fs.existsSync(sqlFile)) {
      console.warn(`⚠️  Skipping ${name} — no migration.sql`);
      return null;
    }
    const sql = fs.readFileSync(sqlFile, 'utf-8');
    return { name, sql };
  })
  .filter(Boolean);

// Build the TypeScript source
const lines = [
  '// AUTO-GENERATED by scripts/bundle-migrations.js — DO NOT EDIT',
  '// Re-run `node scripts/bundle-migrations.js` after adding Prisma migrations.',
  '',
  'export interface BundledMigration {',
  '  name: string;',
  '  sql: string;',
  '}',
  '',
  'export const MIGRATIONS: BundledMigration[] = [',
];

for (const { name, sql } of migrations) {
  // Escape backticks in the SQL (rare but possible)
  const escaped = sql.replace(/`/g, '\\`').replace(/\${/g, '\\${');
  lines.push(`  {`);
  lines.push(`    name: ${JSON.stringify(name)},`);
  lines.push(`    sql: \`${escaped}\`,`);
  lines.push(`  },`);
}

lines.push('];');
lines.push('');

fs.writeFileSync(OUT_FILE, lines.join('\n'), 'utf-8');

console.log(`✅ Bundled ${migrations.length} migration(s) → src/migrations-bundle.ts`);
migrations.forEach(m => console.log(`   • ${m.name}`));